type DeepPartial<T> = {
  [P in keyof T]?: T[P] extends object ? DeepPartial<T[P]> : T[P];
};

type DeepReadonly<T> = {
  readonly [P in keyof T]: T[P] extends object ? DeepReadonly<T[P]> : T[P];
};

interface User {
  name: string;
  address: {
    street: string;
    city: string;
  };
}

const partial: DeepPartial<User> = { address: { city: "NYC" } };
const frozen: DeepReadonly<User> = { name: "Al", address: { street: "1st", city: "NYC" } };
